module top_module(Q, CLK, RST, LOAD, D);output [3:0] Q;
  input CLK, RST, LOAD;
  input [3:0] D;

  reg [3:0] obf_count;

  always @(posedge CLK) begin
    if (RST) begin
      obf_count <= 4'b0000;
    end
    else if (LOAD) begin
      obf_count <= D;
    end
    else begin
      obf_count <= obf_count + 1;
    end
  end

  assign Q = obf_count;

endmodule
